INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (1109650513, 'officer_tooltip_description_52001', '<color=#309BBF>Seize the time!</color>
On round start, Admiral Picard has a <color=#40FF60>{1:#,#%}</color> chance to apply <color=#FFC926>Morale</color> for 3 rounds against a player ship.

<color=#309BBF>This far, no further!</color>
Admiral Picard increases your ship Weapon Damage by <color=#40FF60>{2:#,#%}</color> on combat start against a player Explorer for the duration of combat.', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (1109650513, 'officer_tooltip_description_short_52001', '<color=#309BBF>Seize the time!</color>
