INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (3484257385, 'officer_tooltip_description_53001', '<color=#309BBF>Death to the Opposition!</color>
On round start, Worf has <color=#40FF60>{1:#,#%}</color> chance to apply <color=#FFC926>Hull Breach</color> for 3 rounds against a player ship.

<color=#309BBF>Assimilate this!</color>
Worf increases your ship base Weapon Damage by <color=#40FF60>{2:#,#%}</color> on combat start against a player Interceptor for the duration of combat.', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (3484257385, 'officer_tooltip_description_short_53001', '<color=#309BBF>Death to the Opposition!</color>
On round start, Worf has <color=#40FF60>{1:#,#%}</color> chance to apply <color=#FFC926>Hull Breach</color> for 3 rounds against a player ship.

