INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (2836324820, 'officer_tooltip_description_53002', '<color=#309BBF>Fire from Will!</color>
On round start, Riker has <color=#40FF60>{1:#,#%}</color> chance to apply <color=#FFC926>Burning</color> for 3 rounds against a player ship.

<color=#309BBF>We''re through running!</color>
Riker increases your base ship Weapon Damage by <color=#40FF60>{2:#,#%}</color> on combat start against a player Battleship for the duration of combat.', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (2836324820, 'officer_tooltip_description_short_53002', '<color=#309BBF>Fire from Will!</color>
On round start, Riker has <color=#40FF60>{1:#,#%}</color> chance to apply <color=#FFC926>Burning</color> for 3 rounds against a player ship.

<color=#309BBF>We''re through running!</color>
