INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (3020118241, 'officer_tooltip_description_short_50303', '<color=#309BBF>Combatant</color>
Provides buffs against Players.

<color=#309BBF>Fabricator</color>
Provides Refinery related buffs.

<color=#309BBF>Scientist</color>
Provides Research and other fascinating buffs.', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (3020118241, 'officer_flavor_text_50303', 'It has been a long road, but at last Seven of Nine has achieved her goal of joining Starfleet. However, Seven’s struggles are not yet over. The reality of life proves just as difficult for the former Borg, working alongside those who remember all too well the friends and colleagues lost to the Collective.

After years wrestling with her identity, fighting to regain her humanity under the mentorship of Captain Janeway aboard the USS Voyager, Seven eventually attained a sense of equilibrium. That equilibrium was challenged however when she returned to the Alpha Quadrant and found herself rejected by Starfleet, despite her obvious talents. 

Dismissed by those she had idolized, Seven became a rootless bounty hunter, until her dealings brought her into contact with Jean-Luc Picard and back once more into the sphere of Starfleet. This time, with both Picard and Janeway vouching for her, she finally earned the right to wear the uniform.

Now, having attained the position of a high ranking serving officer aboard a Starfleet vessel, she has even more to prove than ever.', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (3020118241, 'officer_name_50303', 'Seven of Nine', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (3020118241, 'officer_name_short_50303', 'SEVEN', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (1421610149, 'officer_tooltip_description_54001', '<color=#309BBF>Unfit To Lead</color>
This Captain''s Maneuver has no effect.

<color=#309BBF>Over My Dead Program</color>
When you take hull damage from a non-Player hostile or Armada, The Doctor increases your Armor, Shield Deflection, and Dodge by <color=#40FF60>+{2:#,#%}</color> of Health for 2 rounds. (cumulative).
<i>(Weapons with multiple shots will only trigger this ability once per attack.)</i>

<color=#309BBF>Renaissance Man</color>
Increases all resources dropped by hostiles by <color=#40FF60>+{4:#,#%}</color>.', '2025-08-13 17:11:38');
