INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (3439368035, 'officer_tooltip_description_short_50304', '<color=#309BBF>Tactical</color>
Provides buffs against Hostiles.

<color=#309BBF>Admiral</color>
Provides buffs against Armadas.

<color=#309BBF>Scientist</color>
Provides Research and other fascinating buffs.', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (3439368035, 'officer_flavor_text_50304', 'Kathryn Janeway was one of the most decorated Captains in Starfleet history. Voyager''s journey through the Delta Quadrant was unprecedented and filled with new discoveries - and unforeseen dangers. Not since Captain James T. Kirk has a starship Captain made first contact with as many new species and ventured so far into heretofore unknown space. 

It is no surprise, therefore, that upon successfully leading Voyager and her crew home, Captain Janeway was quickly promoted to the rank of Vice Admiral at Starfleet Command. But this was not the first rendition of Vice Admiral Janeway we saw. 

In an alternate timeline where Voyager took an additional 16 years to get home, Vice Admiral Janeway was determined to find a way to go back and prevent the losses that they bore after so long traversing the Delta Quadrant. Vice Admiral Janeway was willing to give up her life - her very reality - for the good of her crew.

"Never abandon a member of your crew." Words Janeway lived by.

By 2385 Kathryn Janeway had achieved the rank of Admiral, and the ability to affect change at the highest levels of Starfleet Command. She remains a legend, a titan among titans; one of the greatest Starfleet Captains to have ever commanded a starship. Her story is one of strength, perseverance, and hope in the face of the unknown.', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (3439368035, 'officer_name_50304', 'Admiral Janeway', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (3439368035, 'officer_name_short_50304', 'JANEWAY', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (1116563882, 'officer_tooltip_description_58001', '<color=#309BBF>Vocal Jazz</color>
On combat start against players, Carol Freeman increases your shots by <color=#40FF60>+{0:#,#%}</color>.

<color=#309BBF>Cerritos Strong!</color>
On round start, if the enemy player has <color=#FFC926>any state</color>, Carol Freeman increases your Isolytic Cascade damage by <color=#40FF60>+{2:#,#%}</color> for 1 round.

Isolytic Cascade multiplies your <color=#40FF60>total damage</color>, including <color=#40FF60>Isolytic Damage</color>, and all research and other bonuses.

States:<color=#FFC926> Morale, Burning, Hull Breach, Assimilated</color>', '2025-08-13 17:11:38');
