INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (2852482387, 'officer_tooltip_description_58002', '<color=#309BBF>Loyal to a Fault</color>
This Captain''s Maneuver has no effect.

<color=#309BBF>Setting My Fists to Stun</color>
On round start, if on an Explorer with <color=#FFC926>Morale</color>, Jack Ransom increases your Isolytic Cascade damage by <color=#40FF60>+{2:#,#%}</color> for 1 round against players.

Isolytic Cascade multiplies your <color=#40FF60>total damage</color>, including <color=#40FF60>Isolytic Damage</color>, and all research and other bonuses.

<color=#309BBF>Exaggerated Confidence</color>
On round start, if on an Interceptor and enemy player has <color=#FFC926>Hull Breach</color>, Jack Ransom increases your Isolytic Defense by <color=#40FF60>+{4:#,#%}</color> for 1 round.', '2025-08-13 17:11:38');
