INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (3013113875, 'officer_tooltip_description_59002', '<color=#309BBF>Chief Medical Officer</color>
This Captain''s Maneuver has no effect.

<color=#309BBF>Make a Mess</color>
On round start, Dr. T''Ana has <color=#40FF60>{3:#,#%}</color> chance to apply a <color=#FFC926>random State</color> to the enemy player''s ship for 3 rounds.

Random States:<color=#FFC926> Morale, Burning, Hull Breach</color>

<color=#309BBF>Bedside Manner</color>
On round start against a player, Dr. T''Ana increases Isolytic Defense by <color=#40FF60>{4:#,#%}</color> for 1 round.', '2025-08-13 17:11:38');
