INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (182221633, 'officer_tooltip_description_63003', '<color=#309BBF>Chain of Command</color>
This Captain''s Maneuver has no effect.

<color=#309BBF>Plan For The Future</color>
Increase the amount of raw Ore, Crystal and Gas collected while mining with any ship by an extra <color=#40FF60>{2:#,#%}</color>, without draining the mining node faster.

<color=#309BBF>Reclaiming Lives</color>
At the beginning of each round of combat Hugh repairs <color=#40FF60>{4:#,#%}</color> of hull damage taken in the previous round of combat.', '2025-08-13 17:11:38');
