INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (1848943130, 'officer_flavor_text_64002', '<color=#40CFFF>CLASS:</color> SCIENCE
<color=#40CFFF>GROUP:</color> ENTERPRISE NX-01
<color=#40CFFF>FACTION:</color> FEDERATION

One of the first aliens to serve aboard the Enterprise, Doctor Phlox of Denobula is one of its most beloved, most valuable crew members.
Despite having only six months of service within Starfleet, the good Doctor Phlox was selected to assist the Enterprise in her maiden voyage following a miraculous treatment of a dying Klingon warrior.
Although his patient would eventually be captured by the Suliban, Phlox continued to serve with distinction aboard the Enterprise, proving himself an invaluable member of the crew on numerous occasions.
Even considering his odd propensity of collecting and cataloging odd alien fauna, one could not ask for a better physician, especially if one’s life is on the line.', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (1848943130, 'officer_name_64002', 'Phlox', '2025-08-13 17:11:38');
