INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (473853704, 'officer_tooltip_description_71901', '<color=#309BBF>Chain of Command</color>
This Officer does not have a Captain''s Maneuver. Equipping this Officer as the captain of a ship provides no benefit.

<color=#309BBF>Honor Among Thieves</color>
On combat start against Invading Entities, increases <color=#6BB7FF>Apex Barrier</color> by <color=#40FF60>{2:#}</color>.

<color=#309BBF>The Winning Gambit</color>
When hit by an Armada or Hostile, increases Critical Hit chance by <color=#40FF60>{4:#,#%}</color> for 4 rounds
(Weapons with multiple shots will only trigger this ability once per attack).', '2025-08-13 17:11:38');
